1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const LOYALTY_THRESHOLD = 2;
21	const LOYALTY_RATE = 0.2;
22	
23	interface QuoteStep {
24	  op: "quote";
25	  items: Item[];
26	}
27	
28	interface Damage {
29	  itemType: string;
30	  amount: number;
31	}
32	
33	interface ClaimStep {
34	  op: "claim";
35	  policy: number;
36	  incident: { cause: string; damages: Damage[] };
37	}
38	
39	type Step = QuoteStep | ClaimStep;
40	
41	interface Customer {
42	  yearsWithMHPCO: number;
43	}
44	
45	interface Scenario {
46	  customer: Customer;
47	  steps: Step[];
48	}
49	
50	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
51	const COMPONENT_BASE = 25;
52	const BLOCK_SIZE = 3;
53	const BLOCK_BASE = 60;
54	
55	const componentBase = (count: number): number =>
56	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
57	
58	const lookupByType = (
59	  type: string,
60	  componentValue: number,
61	  mainItemValues: Record<string, number>,
62	): number =>
63	  COMPONENT_TYPES.has(type) ? componentValue : (mainItemValues[type] ?? 0);
64	
65	const unitBase = (type: string): number =>
66	  lookupByType(type, COMPONENT_BASE, BASE_PREMIUMS);
67	
68	const baseForType = (type: string, count: number): number =>
69	  COMPONENT_TYPES.has(type)
70	    ? componentBase(count)
71	    : unitBase(type) * count;
72	
73	const countByType = (items: Item[]): Map<string, number> =>
74	  items.reduce(
75	    (counts, item) =>
76	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
77	    new Map<string, number>(),
78	  );
79	
80	const baseForItems = (items: Item[]): number =>
81	  [...countByType(items)].reduce(
82	    (total, [type, count]) => total + baseForType(type, count),
83	    0,
84	  );
85	
86	const isHighlyEnchanted = (item: Item): boolean =>
87	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
88	
89	const surchargeRate = (item: Item): number =>
90	  ((item.cursed ?? false) ? CURSE_RATE : 0) +
91	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
92	
93	const itemSurcharges = (item: Item): number =>
94	  unitBase(item.type) * surchargeRate(item);
95	
96	const firstInsuranceSurcharge = (policyBase: number): number =>
97	  policyBase * FIRST_INSURANCE_RATE;
98	
99	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
100	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
101	
102	const priceQuote = (items: Item[], customer: Customer): { premium: number } => {
103	  const policyBase = baseForItems(items);
104	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
105	  const premium = Math.ceil(
106	    policyBase +
107	      surcharges +
108	      firstInsuranceSurcharge(policyBase) -
109	      loyaltyDiscount(policyBase, customer) +
110	      PROCESSING_FEE,
111	  );
112	  return { premium };
113	};
114	
115	const DEDUCTIBLE = 100;
116	const CAP_MULTIPLIER = 2;
117	const HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD = 8;
118	const REIMBURSE_RATE = 0.5;
119	
120	const INSURANCE_VALUES: Record<string, number> = {
121	  sword: 1000,
122	  amulet: 600,
123	  staff: 800,
124	  potion: 400,
125	};
126	const COMPONENT_INSURANCE_VALUE = 250;
127	
128	const insuranceValue = (type: string): number =>
129	  lookupByType(type, COMPONENT_INSURANCE_VALUE, INSURANCE_VALUES);
130	
131	const insuranceSum = (items: Item[]): number =>
132	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
133	
134	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
135	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD
136	    ? damage.amount * REIMBURSE_RATE
137	    : damage.amount;
138	
139	const damagePayout = (damage: Damage, items: Item[]): number => {
140	  const item = items.find((candidate) => candidate.type === damage.itemType);
141	  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
142	};
143	
144	const processClaim = (
145	  step: ClaimStep,
146	  steps: Step[],
147	): { payout: number; remainingCap: number } => {
148	  const policyStep = steps[step.policy] as QuoteStep;
149	  const cap = insuranceSum(policyStep.items) * CAP_MULTIPLIER;
150	  const desired = step.incident.damages.reduce(
151	    (sum, damage) => sum + damagePayout(damage, policyStep.items),
152	    0,
153	  );
154	  const payout = Math.floor(Math.min(desired, cap));
155	  return { payout, remainingCap: cap - payout };
156	};
157	
158	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
159	  const results = scenario.steps.map((step) =>
160	    step.op === "quote"
161	      ? priceQuote(step.items, scenario.customer)
162	      : processClaim(step, scenario.steps),
163	  );
164	  return { results };
165	};
